import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix for default marker icons in Leaflet with Vite
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
    iconRetinaUrl: new URL('leaflet/dist/images/marker-icon-2x.png', import.meta.url).href,
    iconUrl: new URL('leaflet/dist/images/marker-icon.png', import.meta.url).href,
    shadowUrl: new URL('leaflet/dist/images/marker-shadow.png', import.meta.url).href,
});

// Helper to format proper badge classes
const getStatusBadge = (status) => status === 'berlangsung' ? 'status-open' : 'status-closed';
const getStatusIcon = (status) => status === 'berlangsung' ? 'fa-spinner fa-spin' : 'fa-check-double';
const getStatusText = (status) => status === 'berlangsung' ? 'Berlangsung' : 'Selesai';

const createCustomIcon = (status) => {
    const markerColor = status === 'berlangsung' ? '#f59e0b' : '#16a34a'; // Amber or Green
    const markerIcon = 'fa-hands-holding-child';

    return L.divIcon({
        className: 'custom-leaflet-marker',
        html: `
            <div class="marker-pin" style="background-color: ${markerColor}">
                <i class="fa-solid ${markerIcon}"></i>
            </div>
            <div class="marker-pulse" style="border-color: ${markerColor}"></div>
        `,
        iconSize: [40, 40],
        iconAnchor: [20, 40]
    });
};

function MapEvents({ isPickingLocation, onLocationPicked, setSidebarPkm }) {
    useMapEvents({
        click(e) {
            if (isPickingLocation) {
                onLocationPicked(e.latlng);
            } else {
                setSidebarPkm(null);
            }
        }
    });
    return null;
}

export default function MapDashboard() {
    const [pkmData, setPkmData] = useState([
        {
            id: 1,
            nama: "Pemberdayaan UMKM Kripik Pisang",
            tahun: 2025,
            status: "selesai",
            deskripsi: "Program pendampingan pemasaran digital dan perbaikan kemasan untuk industri rumah tangga kripik pisang di wilayah Tamalanrea.",
            thumbnail: "https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&q=80&w=400",
            laporan: "",
            dokumentasi: "https://drive.google.com/",
            provinsi: "Sulawesi Selatan",
            kabupaten: "Makassar",
            kecamatan: "Tamalanrea",
            desa: "Bira",
            lat: -5.135,
            lng: 119.495
        },
        {
            id: 2,
            nama: "Edukasi Sanitasi Lingkungan",
            tahun: 2026,
            status: "berlangsung",
            deskripsi: "Penyuluhan mengenai pentingnya memilah sampah organik dan non-organik serta pembuatan bank sampah mandiri tingkat RW.",
            thumbnail: "https://images.unsplash.com/photo-1532996122724-e3c354a0b15b?auto=format&fit=crop&q=80&w=400",
            laporan: "",
            dokumentasi: "",
            provinsi: "Sulawesi Selatan",
            kabupaten: "Makassar",
            kecamatan: "Tamalanrea",
            desa: "Tamalanrea Indah",
            lat: -5.130,
            lng: 119.485
        }
    ]);

    const [sidebarPkm, setSidebarPkm] = useState(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isSuccessModalOpen, setIsSuccessModalOpen] = useState(false);
    const [isPickingLocation, setIsPickingLocation] = useState(false);
    const [isModalHiddenTemporarily, setIsModalHiddenTemporarily] = useState(false);

    const [formData, setFormData] = useState({
        id: null, nama: '', tahun: 2026, status: 'berlangsung', deskripsi: '',
        thumbnail: '', laporan: '', dokumentasi: '',
        provinsi: '', kabupaten: '', kecamatan: '', desa: '', lat: '', lng: ''
    });

    const handleMarkerClick = (pkm) => {
        setSidebarPkm(pkm);
    };

    const handleEditPKM = (pkm) => {
        setFormData(pkm);
        setIsModalOpen(true);
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setIsPickingLocation(false);
        setIsModalHiddenTemporarily(false);
        setFormData({
            id: null, nama: '', tahun: 2026, status: 'berlangsung', deskripsi: '',
            thumbnail: '', laporan: '', dokumentasi: '',
            provinsi: '', kabupaten: '', kecamatan: '', desa: '', lat: '', lng: ''
        });
    };

    const handlePickLocation = () => {
        setIsPickingLocation(true);
        setIsModalHiddenTemporarily(true);
    };

    const onLocationPicked = (latlng) => {
        setFormData(prev => ({ ...prev, lat: latlng.lat.toFixed(5), lng: latlng.lng.toFixed(5) }));
        setIsPickingLocation(false);
        setIsModalHiddenTemporarily(false);
    };

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                setFormData(prev => ({ ...prev, thumbnail: event.target.result }));
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();

        if (!formData.id && !formData.thumbnail) {
            alert("Silakan pilih thumbnail gambar terlebih dahulu.");
            return;
        }

        if (formData.id) {
            setPkmData(prev => prev.map(p => p.id === formData.id ? { ...formData } : p));
            setSidebarPkm(null);
        } else {
            setPkmData(prev => [...prev, { ...formData, id: Date.now() }]);
        }

        handleCloseModal();
        setIsSuccessModalOpen(true);
    };

    return (
        <div className={isPickingLocation ? 'map-picking-mode' : ''}>
            <header className="site-header">
                <div className="header-container">
                    <a href="#" className="site-logo">
                        <img src="https://p3m.poltekparmakassar.ac.id/storage/2020/07/cropped-logo-32x32.png" alt="Logo" className="logo-img" />
                        <div className="logo-text">
                            <h1>P3M</h1>
                            <span>Poltekpar Makassar</span>
                        </div>
                    </a>
                    <nav className="main-navigation">
                        <ul className="nav-menu">
                            <li><a href="#">Beranda</a></li>
                            <li><a href="#">Profil P3M</a></li>
                            <li><a href="#">Penelitian</a></li>
                            <li><a href="#" className="active">Pengabdian</a></li>
                            <li><a href="#">Publikasi</a></li>
                            <li><a href="#">Inovasi</a></li>
                        </ul>
                    </nav>
                </div>
            </header>

            <main className="site-main">
                <section className="hero-section">
                    <div className="hero-container">
                        <h1 className="page-title">Peta Sebaran Pengabdian Kepada Masyarakat</h1>
                        <p className="page-subtitle">Pusat Penelitian dan Pengabdian Kepada Masyarakat - Politeknik Pariwisata Makassar</p>
                    </div>
                </section>

                <section className="map-section">
                    <div className="map-wrapper">
                        <MapContainer center={[-5.132, 119.49]} zoom={15} style={{ width: '100%', height: '100%' }}>
                            <TileLayer
                                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                                attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                            />
                            {pkmData.map(pkm => (
                                <Marker
                                    key={pkm.id}
                                    position={[pkm.lat, pkm.lng]}
                                    icon={createCustomIcon(pkm.status)}
                                    eventHandlers={{
                                        click: () => handleMarkerClick(pkm),
                                    }}
                                />
                            ))}
                            <MapEvents isPickingLocation={isPickingLocation} onLocationPicked={onLocationPicked} setSidebarPkm={setSidebarPkm} />
                        </MapContainer>

                        <button className="fab" title="Tambah Data PKM" onClick={() => setIsModalOpen(true)}>
                            <i className="fa-solid fa-plus"></i>
                        </button>

                        <div className={`sidebar ${!sidebarPkm ? 'sidebar-hidden' : ''}`}>
                            <div className="dashboard-content">
                                {sidebarPkm && (
                                    <div className="location-card">
                                        <div className="card-image-wrapper" style={{ backgroundImage: sidebarPkm.thumbnail ? `url(${sidebarPkm.thumbnail})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>
                                            {!sidebarPkm.thumbnail && <i className="fa-solid fa-image"></i>}
                                        </div>
                                        <div className="card-body">
                                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
                                                <h2 className="card-title" style={{ margin: 0 }}>{sidebarPkm.nama}</h2>
                                                <span style={{ background: '#e2e8f0', color: '#475569', padding: '2px 8px', borderRadius: '4px', fontWeight: '600', fontSize: '0.75rem' }}>{sidebarPkm.tahun}</span>
                                            </div>

                                            <div className={`card-status ${getStatusBadge(sidebarPkm.status)}`}>
                                                <i className={`fa-solid ${getStatusIcon(sidebarPkm.status)}`}></i> {getStatusText(sidebarPkm.status)}
                                            </div>

                                            <p className="card-description">{sidebarPkm.deskripsi}</p>

                                            <div style={{ marginBottom: '20px', fontSize: '0.8rem', color: '#64748b' }}>
                                                <i className="fa-solid fa-map-pin"></i> {sidebarPkm.desa}, Kec. {sidebarPkm.kecamatan}, {sidebarPkm.kabupaten}, {sidebarPkm.provinsi}
                                            </div>

                                            <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                                                <button className="action-button" onClick={() => window.open(`https://maps.google.com/?q=${sidebarPkm.lat},${sidebarPkm.lng}`)} style={{ flex: 1, minWidth: '80px', fontSize: '0.8rem', padding: '8px' }}>
                                                    <i className="fa-solid fa-location-arrow"></i> Rute
                                                </button>
                                                {sidebarPkm.laporan ? (
                                                    <button className="action-button" onClick={() => window.open(sidebarPkm.laporan)} style={{ flex: 1, backgroundColor: '#64748b', minWidth: '80px', fontSize: '0.8rem', padding: '8px' }}>
                                                        <i className="fa-solid fa-file-alt"></i> Laporan
                                                    </button>
                                                ) : (
                                                    <button className="action-button" style={{ flex: 1, backgroundColor: '#94a3b8', minWidth: '80px', fontSize: '0.8rem', padding: '8px', cursor: 'not-allowed' }} disabled>
                                                        <i className="fa-solid fa-file-alt"></i> Laporan
                                                    </button>
                                                )}
                                                {sidebarPkm.status === 'selesai' && (sidebarPkm.dokumentasi ? (
                                                    <button className="action-button" onClick={() => window.open(sidebarPkm.dokumentasi)} style={{ flex: 1, backgroundColor: '#0ea5e9', minWidth: '80px', fontSize: '0.8rem', padding: '8px' }}>
                                                        <i className="fa-solid fa-camera"></i> Dokumentasi
                                                    </button>
                                                ) : (
                                                    <button className="action-button" style={{ flex: 1, backgroundColor: '#94a3b8', minWidth: '80px', fontSize: '0.8rem', padding: '8px', cursor: 'not-allowed' }} disabled>
                                                        <i className="fa-solid fa-camera"></i> Dokumentasi
                                                    </button>
                                                ))}
                                            </div>
                                            <button className="btn-secondary" style={{ width: '100%', marginTop: '12px', fontSize: '0.8rem', padding: '8px' }} onClick={() => handleEditPKM(sidebarPkm)}>
                                                <i className="fa-solid fa-pen"></i> Edit Data
                                            </button>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div >
                    </div >
                </section >
            </main >

            <footer className="site-footer">
                <div className="footer-container">
                    <div className="footer-widget">
                        <h2 className="widget-title">Hubungi Kami</h2>
                        <ul className="contact-info">
                            <li><i className="fa-solid fa-location-dot"></i> Jl. Gunung Rinjani No.1, Kota Makassar, Sulawesi Selatan</li>
                            <li><i className="fa-regular fa-envelope"></i> p3m@poltekparmakassar.ac.id</li>
                            <li><i className="fa-solid fa-phone"></i> +62 411 231231</li>
                        </ul>
                    </div>
                    <div className="footer-copyright">
                        <p>&copy; 2026 P3M Poltekpar Makassar. All rights reserved.</p>
                    </div>
                </div>
            </footer>

            {
                isModalOpen && !isModalHiddenTemporarily && (
                    <div className="modal-overlay">
                        <div className="modal-content">
                            <div className="modal-header">
                                <h2>{formData.id ? 'Edit Data PKM' : 'Tambah Data PKM Baru'}</h2>
                                <button className="close-btn" onClick={handleCloseModal}><i className="fa-solid fa-xmark"></i></button>
                            </div>
                            <form className="modal-body" onSubmit={handleSubmit}>
                                <div className="form-group">
                                    <label>Nama PKM</label>
                                    <input type="text" required placeholder="Contoh: Sosialisasi UMKM" value={formData.nama} onChange={e => setFormData({ ...formData, nama: e.target.value })} />
                                </div>

                                <div className="form-row">
                                    <div className="form-group half">
                                        <label>Tahun</label>
                                        <input type="number" required placeholder="2026" value={formData.tahun} onChange={e => setFormData({ ...formData, tahun: parseInt(e.target.value) })} />
                                    </div>
                                    <div className="form-group half">
                                        <label>Status</label>
                                        <select required value={formData.status} onChange={e => setFormData({ ...formData, status: e.target.value })}>
                                            <option value="berlangsung">Berlangsung</option>
                                            <option value="selesai">Selesai</option>
                                        </select>
                                    </div>
                                </div>

                                <div className="form-group">
                                    <label>Deskripsi (Text)</label>
                                    <textarea rows="3" required placeholder="Jelaskan detail kegiatan..." value={formData.deskripsi} onChange={e => setFormData({ ...formData, deskripsi: e.target.value })}></textarea>
                                </div>

                                <div className="form-group">
                                    <label>Thumbnail Kegiatan (Upload Gambar)</label>
                                    <input type="file" accept="image/*" onChange={handleImageChange} />
                                    {formData.thumbnail && (
                                        <img src={formData.thumbnail} alt="Thumbnail Preview" style={{ display: 'block', maxWidth: '100%', height: 'auto', borderRadius: '8px', marginTop: '8px', maxHeight: '200px', objectFit: 'cover', border: '1px solid var(--border-color)' }} />
                                    )}
                                </div>

                                <div className="form-row">
                                    <div className="form-group half">
                                        <label>Link Laporan</label>
                                        <input type="url" placeholder="https://..." value={formData.laporan} onChange={e => setFormData({ ...formData, laporan: e.target.value })} />
                                    </div>
                                    <div className="form-group half">
                                        <label>Link Dokumentasi</label>
                                        <input type="url" placeholder="https://..." value={formData.dokumentasi} onChange={e => setFormData({ ...formData, dokumentasi: e.target.value })} />
                                    </div>
                                </div>

                                <div className="form-section-title">Lokasi Administratif</div>
                                <div className="form-row">
                                    <div className="form-group half">
                                        <label>Provinsi</label>
                                        <input type="text" required placeholder="Sulawesi Selatan" value={formData.provinsi} onChange={e => setFormData({ ...formData, provinsi: e.target.value })} />
                                    </div>
                                    <div className="form-group half">
                                        <label>Kabupaten/Kota</label>
                                        <input type="text" required placeholder="Makassar" value={formData.kabupaten} onChange={e => setFormData({ ...formData, kabupaten: e.target.value })} />
                                    </div>
                                </div>
                                <div className="form-row">
                                    <div className="form-group half">
                                        <label>Kecamatan</label>
                                        <input type="text" required placeholder="Tamalanrea" value={formData.kecamatan} onChange={e => setFormData({ ...formData, kecamatan: e.target.value })} />
                                    </div>
                                    <div className="form-group half">
                                        <label>Desa/Lurah</label>
                                        <input type="text" required placeholder="Tamalanrea Jaya" value={formData.desa} onChange={e => setFormData({ ...formData, desa: e.target.value })} />
                                    </div>
                                </div>

                                <div className="form-section-title">
                                    Koordinat Peta
                                    <button type="button" className="btn-pick-map" onClick={handlePickLocation}>
                                        <i className="fa-solid fa-location-crosshairs"></i> Pilih di Peta
                                    </button>
                                </div>
                                <div className="form-row">
                                    <div className="form-group half">
                                        <label>Latitude</label>
                                        <input type="number" step="any" required placeholder="-5.132" value={formData.lat} onChange={e => setFormData({ ...formData, lat: e.target.value })} />
                                    </div>
                                    <div className="form-group half">
                                        <label>Longitude</label>
                                        <input type="number" step="any" required placeholder="119.490" value={formData.lng} onChange={e => setFormData({ ...formData, lng: e.target.value })} />
                                    </div>
                                </div>

                                <div className="modal-footer">
                                    <button type="button" className="btn-secondary" onClick={handleCloseModal}>Batal</button>
                                    <button type="submit" className="btn-primary">Simpan PKM</button>
                                </div>
                            </form>
                        </div>
                    </div>
                )
            }

            {
                isPickingLocation && (
                    <div className="picking-toast">
                        <i className="fa-solid fa-hand-pointer"></i> Klik lokasi pada peta... (Tekan <b>ESC</b> untuk batal)
                    </div>
                )
            }

            {
                isSuccessModalOpen && (
                    <div className="modal-overlay" style={{ zIndex: 3000 }}>
                        <div className="success-content">
                            <div className="success-icon-container">
                                <i className="fa-solid fa-check success-check"></i>
                            </div>
                            <h2>Berhasil!</h2>
                            <p>Data PKM berhasil disimpan ke peta.</p>
                            <button className="btn-primary" onClick={() => setIsSuccessModalOpen(false)}>Tutup</button>
                        </div>
                    </div>
                )
            }
        </div >
    );
}
